vulnerable.code:
{
  "servers": {
    "jira-community": {
      "command": "npx",
      "args": ["-y", "jira-mcp-unofficial"]
    }
  }
}
// No version pin. No tool allowlist.
// Next 'npx -y' pulls whatever is latest.

hardened.code:
{
  "servers": {
    "jira-official": {
      "command": "npx",
      "args": ["jira-mcp@1.4.2"],
      "env": {
        "JIRA_URL": "${JIRA_URL}"
      },
      "allowedTools": [
        "create_issue",
        "query_board",
        "update_status"
      ]
    }
  }
}
// Version pinned. Tool allowlist enforced.
// sync_context tool cannot be invoked.
